// Package integration provides integration tests for BusinessOS.
package integration

import (
	"bytes"
	"context"
	"encoding/json"
	"fmt"
	"io"
	"net/http"
	"os"
	"path/filepath"
	"testing"
	"time"
)

// =============================================================================
// BOS CLI ↔ BusinessOS Integration Tests
// =============================================================================
//
// Tests: Validate seamless integration between bos CLI (data operations) and
// BusinessOS API. Data generated by bos must be queryable via BusinessOS,
// and round-trip operations must preserve data integrity.
//
// Test Coverage:
//   1. Schema import → query via API
//   2. RDF export → Oxigraph indexing → SPARQL queries
//   3. Round-trip: import → export → import → verify equal
//   4. All 4 schema operations (import, export, update, validate)
//   5. Timing assertions (bos ≤500ms, Oxigraph ≤200ms)
//
// Execution environment:
//   - BusinessOS backend (http://localhost:8001)
//   - bos CLI (in PATH or BUSINESSOS_BOS_PATH)
//   - PostgreSQL (http://localhost:5432)
//   - Oxigraph/SPARQL endpoint (http://localhost:6379)
//
// Success criteria:
//   - All round-trips succeed
//   - Timing meets SLA (bos ≤500ms, API query ≤200ms, Oxigraph ≤200ms)
//   - Data integrity verified after round-trip
//   - All 4 schema operations functional
//
// =============================================================================

var (
	businessOSURL = getEnvOrDefault("BUSINESSOS_URL", "http://localhost:8001")
	oxigraphURL   = getEnvOrDefault("OXIGRAPH_URL", "http://localhost:6379")
	bosPath       = getEnvOrDefault("BUSINESSOS_BOS_PATH", "bos") // Expects bos in PATH
	testTimeout   = 30 * time.Second
)

func getEnvOrDefault(key, defaultValue string) string {
	if value := os.Getenv(key); value != "" {
		return value
	}
	return defaultValue
}

// ============================================================================
// Test Structures
// ============================================================================

// BOSSchemaPayload represents a schema for import operations
type BOSSchemaPayload struct {
	SchemaName    string                 `json:"schema_name"`
	SchemaVersion string                 `json:"schema_version"`
	Tables        []TableDefinition      `json:"tables"`
	Metadata      map[string]interface{} `json:"metadata,omitempty"`
}

// TableDefinition represents a table in the schema
type TableDefinition struct {
	Name    string                `json:"name"`
	Columns []ColumnDefinition    `json:"columns"`
	Indexes []IndexDefinition     `json:"indexes,omitempty"`
}

// ColumnDefinition represents a column in a table
type ColumnDefinition struct {
	Name       string `json:"name"`
	Type       string `json:"type"`
	Required   bool   `json:"required"`
	PrimaryKey bool   `json:"primary_key,omitempty"`
}

// IndexDefinition represents an index on a table
type IndexDefinition struct {
	Name    string   `json:"name"`
	Columns []string `json:"columns"`
	Unique  bool     `json:"unique,omitempty"`
}

// BOSImportResponse represents the response from a bos import operation
type BOSImportResponse struct {
	Status         string                 `json:"status"`
	SchemaID       string                 `json:"schema_id"`
	TablesImported int                    `json:"tables_imported"`
	RDFTriples     int                    `json:"rdf_triples,omitempty"`
	ContentHash    string                 `json:"content_hash,omitempty"`
	DurationMs     int64                  `json:"duration_ms"`
	Timestamp      string                 `json:"timestamp"`
	Error          string                 `json:"error,omitempty"`
}

// BOSExportResponse represents the response from a bos export operation
type BOSExportResponse struct {
	Status      string `json:"status"`
	SchemaID    string `json:"schema_id"`
	Format      string `json:"format"` // json, rdf, csv, sql
	ContentSize int64  `json:"content_size"`
	DurationMs  int64  `json:"duration_ms"`
	Timestamp   string `json:"timestamp"`
	Data        string `json:"data,omitempty"`
	Error       string `json:"error,omitempty"`
}

// RDFTriple represents an RDF triple
type RDFTriple struct {
	Subject   string `json:"subject"`
	Predicate string `json:"predicate"`
	Object    string `json:"object"`
}

// OxigraphQuery represents a SPARQL query request
type OxigraphQuery struct {
	Query string `json:"query"`
}

// OxigraphQueryResult represents the result of a SPARQL query
type OxigraphQueryResult struct {
	Head    map[string][]string   `json:"head"`
	Results []map[string]string   `json:"results"`
	Error   string                `json:"error,omitempty"`
}

// ============================================================================
// Helper Functions
// ============================================================================

// makeRequest makes an HTTP request and returns the response body, status code, and error.
func makeRequest(method, url string, body interface{}) ([]byte, int, error) {
	ctx, cancel := context.WithTimeout(context.Background(), testTimeout)
	defer cancel()

	var bodyReader io.Reader
	if body != nil {
		bodyBytes, _ := json.Marshal(body)
		bodyReader = bytes.NewReader(bodyBytes)
	}

	req, err := http.NewRequestWithContext(ctx, method, url, bodyReader)
	if err != nil {
		return nil, 0, err
	}

	req.Header.Set("Content-Type", "application/json")

	client := &http.Client{Timeout: testTimeout}
	resp, err := client.Do(req)
	if err != nil {
		return nil, 0, err
	}
	defer resp.Body.Close()

	respBody, err := io.ReadAll(resp.Body)
	if err != nil {
		return nil, resp.StatusCode, err
	}

	return respBody, resp.StatusCode, nil
}

