// TestBOSTimingAssertions verifies that all operations meet SLA requirements.
func TestBOSTimingAssertions(t *testing.T) {
	schema := createFIBOSchema()

	timings := map[string]int64{
		"import": 500,  // ms
		"export": 200,  // ms
		"query":  200,  // ms
	}

	// Step 1: Test import timing
	importReq := map[string]interface{}{
		"schema": schema,
		"format": "json",
	}
	startTime := time.Now()
	respBody, statusCode, _ := makeRequest(
		"POST",
		fmt.Sprintf("%s/api/bos/schema/import", businessOSURL),
		importReq,
	)
	importDuration := time.Since(startTime).Milliseconds()

	if statusCode != http.StatusOK && statusCode != http.StatusCreated {
		t.Logf("SKIP: Import failed with status %d", statusCode)
		t.SkipNow()
	}

	var importResp BOSImportResponse
	if err := json.Unmarshal(respBody, &importResp); err != nil {
		t.Logf("Failed to parse import response: %v", err)
		t.FailNow()
	}

	if importDuration > timings["import"] {
		t.Logf("FAIL: Import timing %d ms exceeds SLA of %d ms", importDuration, timings["import"])
		t.FailNow()
	}

	schemaID := importResp.SchemaID

	// Step 2: Test export timing
	startTime = time.Now()
	respBody, statusCode, _ = makeRequest(
		"GET",
		fmt.Sprintf("%s/api/bos/schema/export/%s?format=json", businessOSURL, schemaID),
		nil,
	)
	exportDuration := time.Since(startTime).Milliseconds()

	if statusCode != http.StatusOK {
		t.Logf("Export failed with status %d", statusCode)
		t.FailNow()
	}

	if exportDuration > timings["export"] {
		t.Logf("FAIL: Export timing %d ms exceeds SLA of %d ms", exportDuration, timings["export"])
		t.FailNow()
	}

	// Step 3: Test query timing
	queryReq := map[string]interface{}{
		"schema_id": schemaID,
		"query":     "SELECT * FROM fibo_deal LIMIT 10",
	}
	startTime = time.Now()
	respBody, statusCode, _ = makeRequest(
		"POST",
		fmt.Sprintf("%s/api/bos/schema/query", businessOSURL),
		queryReq,
	)
	queryDuration := time.Since(startTime).Milliseconds()

	if statusCode != http.StatusOK {
		t.Logf("Query failed with status %d", statusCode)
		t.FailNow()
	}

	if queryDuration > timings["query"] {
		t.Logf("FAIL: Query timing %d ms exceeds SLA of %d ms", queryDuration, timings["query"])
		t.FailNow()
	}

	t.Logf("All timing assertions passed: import=%dms, export=%dms, query=%dms",
		importDuration, exportDuration, queryDuration)
}

// TestBOSDataIntegrityAcrossOperations verifies that data is not corrupted across operations.
func TestBOSDataIntegrityAcrossOperations(t *testing.T) {
	schema := createFIBOSchema()
	schemaBytes, _ := json.Marshal(schema)

	// Step 1: Import with initial hash
	importReq := map[string]interface{}{
		"schema": schema,
		"format": "json",
	}
	respBody, statusCode, _ := makeRequest(
		"POST",
		fmt.Sprintf("%s/api/bos/schema/import", businessOSURL),
		importReq,
	)

	if statusCode != http.StatusOK && statusCode != http.StatusCreated {
		t.Logf("SKIP: Import failed with status %d", statusCode)
		t.SkipNow()
	}

	var importResp BOSImportResponse
	if err := json.Unmarshal(respBody, &importResp); err != nil {
		t.Logf("Failed to parse import response: %v", err)
		t.FailNow()
	}

	initialHash := importResp.ContentHash
	schemaID := importResp.SchemaID
	t.Logf("Initial content hash: %s", initialHash)

	// Step 2: Export and verify hash
	respBody, statusCode, _ = makeRequest(
		"GET",
		fmt.Sprintf("%s/api/bos/schema/export/%s?format=json", businessOSURL, schemaID),
		nil,
	)

	if statusCode != http.StatusOK {
		t.Logf("Export failed with status %d", statusCode)
		t.FailNow()
	}

	var exportResp BOSExportResponse
	if err := json.Unmarshal(respBody, &exportResp); err != nil {
		t.Logf("Failed to parse export response: %v", err)
		t.FailNow()
	}

	// Parse exported data
	var exportedSchema BOSSchemaPayload
	if err := json.Unmarshal([]byte(exportResp.Data), &exportedSchema); err != nil {
		// Try raw string comparison if not valid JSON
		if string(schemaBytes) != exportResp.Data {
			t.Logf("Exported data does not match imported data")
			t.FailNow()
		}
	}

	// Step 3: Re-import and check hash consistency
	reimportReq := map[string]interface{}{
		"data":   exportResp.Data,
		"format": "json",
	}
	respBody, statusCode, _ = makeRequest(
		"POST",
		fmt.Sprintf("%s/api/bos/schema/import", businessOSURL),
		reimportReq,
	)

	if statusCode != http.StatusOK && statusCode != http.StatusCreated {
		t.Logf("Re-import failed with status %d", statusCode)
		t.FailNow()
	}

	var reimportResp BOSImportResponse
	if err := json.Unmarshal(respBody, &reimportResp); err != nil {
		t.Logf("Failed to parse re-import response: %v", err)
		t.FailNow()
	}

	if initialHash != "" && reimportResp.ContentHash != "" {
		if initialHash != reimportResp.ContentHash {
			t.Logf("Content hash mismatch after round-trip: %s != %s", initialHash, reimportResp.ContentHash)
			t.FailNow()
		}
	}

	t.Logf("Data integrity verified: hash consistent after round-trip")
}

// TestBOSMultipleSchemaImports verifies that multiple schemas can coexist in the system.
func TestBOSMultipleSchemaImports(t *testing.T) {
	fiboSchema := createFIBOSchema()
	healthcareSchema := createHealthcareSchema()

	// Step 1: Import FIBO schema
	fiboReq := map[string]interface{}{
		"schema": fiboSchema,
		"format": "json",
	}
	respBody, statusCode, _ := makeRequest(
		"POST",
		fmt.Sprintf("%s/api/bos/schema/import", businessOSURL),
		fiboReq,
	)

	if statusCode != http.StatusOK && statusCode != http.StatusCreated {
		t.Logf("SKIP: FIBO import failed with status %d", statusCode)
		t.SkipNow()
	}

	var fiboResp BOSImportResponse
	if err := json.Unmarshal(respBody, &fiboResp); err != nil {
		t.Logf("Failed to parse FIBO import response: %v", err)
		t.FailNow()
	}

	fiboID := fiboResp.SchemaID

	// Step 2: Import healthcare schema
	healthcareReq := map[string]interface{}{
		"schema": healthcareSchema,
		"format": "json",
	}
	respBody, statusCode, _ = makeRequest(
		"POST",
		fmt.Sprintf("%s/api/bos/schema/import", businessOSURL),
		healthcareReq,
	)

	if statusCode != http.StatusOK && statusCode != http.StatusCreated {
		t.Logf("Healthcare import failed with status %d", statusCode)
		t.FailNow()
	}

	var healthcareResp BOSImportResponse
	if err := json.Unmarshal(respBody, &healthcareResp); err != nil {
		t.Logf("Failed to parse healthcare import response: %v", err)
		t.FailNow()
	}

	healthcareID := healthcareResp.SchemaID

	// Step 3: Verify both schemas exist independently
	respBody, statusCode, _ = makeRequest(
		"GET",
		fmt.Sprintf("%s/api/bos/schema/export/%s?format=json", businessOSURL, fiboID),
		nil,
	)

	if statusCode != http.StatusOK {
		t.Logf("Failed to retrieve FIBO schema: status %d", statusCode)
		t.FailNow()
	}

	respBody, statusCode, _ = makeRequest(
		"GET",
		fmt.Sprintf("%s/api/bos/schema/export/%s?format=json", businessOSURL, healthcareID),
		nil,
	)

	if statusCode != http.StatusOK {
		t.Logf("Failed to retrieve healthcare schema: status %d", statusCode)
		t.FailNow()
	}

	t.Logf("Successfully imported and verified multiple schemas: FIBO=%s, Healthcare=%s", fiboID, healthcareID)
}

// TestBOSCLICompatibility verifies that bos CLI output is compatible with BusinessOS API parsing.
func TestBOSCLICompatibility(t *testing.T) {
	// This test verifies that if bos CLI is available, its output format
	// matches what BusinessOS expects for import operations.

	tempDir := filepath.Join(os.TempDir(), "bos-integration-test")
	if err := os.MkdirAll(tempDir, 0755); err != nil {
		t.Logf("Failed to create temp directory: %v", err)
		t.FailNow()
	}
	defer os.RemoveAll(tempDir)

	schema := createFIBOSchema()
	schemaFile := filepath.Join(tempDir, "test_schema.json")

	schemaBytes, _ := json.MarshalIndent(schema, "", "  ")
	if err := os.WriteFile(schemaFile, schemaBytes, 0644); err != nil {
		t.Logf("Failed to write schema file: %v", err)
		t.FailNow()
	}

	t.Logf("Schema file created at: %s", schemaFile)
	// If bos CLI is available in PATH, additional validation can be performed here
}
